```typescript
app.post("/api/chat", async (req, res) => {
  const startedAt = Date.now();
  let chatId: string = createChatThreadId();

  try {
    const body = z.object({
      chatId: z.string().uuid().optional(),
      messages: z.array(z.object({
        role: z.enum(["user", "agent", "assistant", "system"]),
        content: z.string(),
        plan: sqlPlanSchema.nullish(),
      })).min(1),
    }).parse(req.body);
    chatId = body.chatId ?? chatId;
    const lastUserMessage = [...body.messages].reverse().find((message) => message.role === "user");

    await ensureChatStore().catch(() => undefined);
    await ensureChatThread(chatId, lastUserMessage?.content?.slice(0, 80)).catch(() => undefined);
    if (lastUserMessage) {
      await saveChatMessage({
        threadId: chatId,
        role: "user",
        content: lastUserMessage.content,
        status: "sent",
      }).catch(() => undefined);
    }

    const result = await sendAgentChat({ messages: body.messages });
    const latencyMs = Date.now() - startedAt;
    await saveChatMessage({
      threadId: chatId,
      role: "agent",
      content: result.content,
      status: "completed",
      operationId: result.operationId,
      plan: result.plan,
      latencyMs,
    }).catch(() => undefined);
    res.json({ content: result.content, operationId: result.operationId, plan: result.plan, statements: result.statements, chatId });
  } catch (error) {
    // ... error handling, saves error message to chat store
    res.status(503).json({ error: ..., chatId });
  }
});
```

The route:
1. Validates the request body (chatId, messages array)
2. Creates/ensures a chat thread in PostgreSQL
3. Saves the user message
4. Calls `sendAgentChat()` with the messages
5. Saves the agent response
6. Returns the result with `content`, `plan`, `operationId`, `statements`, and `chatId`

