## 4. `sendChatMessagesToAgent` Function

**File:** `C:\Users\Zematek\Documents\Projecto-SharePoint\src\client\App.tsx` (lines 787-836)

```typescript
const sendChatMessagesToAgent = async (nextMessages: ChatMessage[], requestChatId: string) => {
  const requestSeq = chatRequestSeqRef.current + 1;
  const controller = new AbortController();
  chatRequestSeqRef.current = requestSeq;
  chatAbortControllerRef.current?.abort();
  chatAbortControllerRef.current = controller;
  setChatMessages(nextMessages);
  setIsAgentThinking(true);
  requestAgentNotificationPermission();

  try {
    const annotationContextMessage = buildAnnotationContextMessage(annotations);
    const payloadMessages: ChatPayloadMessage[] = annotationContextMessage
      ? [annotationContextMessage, ...nextMessages]
      : nextMessages;

    const res = await fetch('/api/chat', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ chatId: requestChatId, messages: payloadMessages }),
      signal: controller.signal,
    });
    const data = await res.json();
    if (chatRequestSeqRef.current !== requestSeq || activeChatIdRef.current !== requestChatId) return;
    if (!res.ok || !data.content) {
      throw new Error(data.error || 'O agente esta indisponivel.');
    }
    setChatMessages(prev => [...prev, {
      role: 'agent',
      content: data.content,
      plan: data.plan ?? null,
    }]);
    notifyAgentResponse();
  } catch (err) {
    // ... error handling
  } finally {
    // ... cleanup
  }
};
```

**Key behavior:**
- Uses a request sequence number + AbortController for race condition protection
- Calls `buildAnnotationContextMessage(annotations)` and prepends it as a system message if annotations exist
- Sends to `/api/chat` with `{ chatId, messages }`
- Appends the agent response to chat messages

